mapper.select:
SELECT
    ,

FROM park_record pr
LEFT JOIN sys_user u ON pr.user_id = u.id
LEFT JOIN park_area s ON pr.area_id = s.id
LEFT JOIN park_space p ON pr.space_id = p.id
WHERE 1=1
AND pr.user_id = #{userId}
AND pr.space_id = #{spaceId}
AND pr.status = #{status}
AND pr.create_time >= #{startTime}
AND pr.create_time <= #{endTime}
ORDER BY pr.create_time DESC
